def solve(grid):
    from collections import Counter
    grid = [row[:] for row in grid]
    H = len(grid)
    W = len(grid[0])
    div_col = None
    for c in range(W):
        vals = set(grid[r][c] for r in range(H))
        if len(vals) == 1 and 0 not in vals:
            div_col = c
            break
    left_cols = list(range(0, div_col))
    right_start = div_col + 1
    right_end = W - 1
    border_vals = []
    for c in range(right_start, W):
        border_vals.extend([grid[0][c], grid[H-1][c]])
    for r in range(H):
        border_vals.extend([grid[r][right_start], grid[r][right_end]])
    border_default = Counter(border_vals).most_common(1)[0][0]
    col_markers = {}
    for c in range(right_start, W):
        v = grid[0][c]
        if v != border_default and v != 0:
            col_markers.setdefault(v, []).append(c)
    row_markers = {}
    for r in range(H):
        v = grid[r][right_start]
        if v != border_default and v != 0:
            row_markers.setdefault(v, []).append(r)
        v2 = grid[r][right_end]
        if v2 != border_default and v2 != 0 and v2 not in [grid[r][right_start]]:
            row_markers.setdefault(v2, []).append(r)
    shapes = {}
    for r in range(H):
        for c in left_cols:
            v = grid[r][c]
            if v != 0:
                shapes.setdefault(v, []).append((r, c))
    shape_data = {}
    for color, cells in shapes.items():
        rs = [r for r, c in cells]
        cs = [c for r, c in cells]
        cr = (min(rs) + max(rs)) / 2.0
        cc = (min(cs) + max(cs)) / 2.0
        offsets = [(r - cr, c - cc) for r, c in cells]
        shape_data[color] = (offsets, cr, cc)
    out = [row[:] for row in grid]
    for r in range(H):
        for c in left_cols:
            out[r][c] = 0
    for color, cells in shapes.items():
        if color not in col_markers or color not in row_markers:
            for r, c in cells:
                out[r][c] = color
    ordered_colors = sorted(shape_data.keys(), key=lambda c: shape_data[c][1], reverse=True)
    for color in ordered_colors:
        if color in col_markers and color in row_markers:
            offsets, cr, cc = shape_data[color]
            for target_r in row_markers[color]:
                for target_c in col_markers[color]:
                    for dr, dc in offsets:
                        nr = int(round(target_r + dr))
                        nc = int(round(target_c + dc))
                        if 0 <= nr < H and 0 <= nc < W:
                            out[nr][nc] = color
    return out

