def solve(grid):
    from collections import deque
    grid = [row[:] for row in grid]
    H = len(grid)
    W = len(grid[0])
    zero_cells = set((r,c) for r in range(H) for c in range(W) if grid[r][c] == 0)
    min_r0 = min(r for r,c in zero_cells)
    max_r0 = max(r for r,c in zero_cells)
    min_c0 = min(c for r,c in zero_cells)
    max_c0 = max(c for r,c in zero_cells)
    bh = max_r0 - min_r0 + 1
    bw = max_c0 - min_c0 + 1
    def is_path(r, c):
        return 0 <= r < H and 0 <= c < W and grid[r][c] in (0, 1, 2)
    def can_be_at(pr, pc):
        return all(is_path(r, c) for r in range(pr, pr+bh) for c in range(pc, pc+bw))
    pos = (min_r0, min_c0)
    q = deque([pos])
    block_dist = {pos: 0}
    farthest = (0, pos)
    while q:
        cr, cc = q.popleft()
        d = block_dist[(cr,cc)]
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = cr+dr, cc+dc
            if (nr, nc) not in block_dist and can_be_at(nr, nc):
                block_dist[(nr, nc)] = d + 1
                q.append((nr, nc))
                if d + 1 > farthest[0]:
                    farthest = (d + 1, (nr, nc))
    target = farthest[1]
    for r, c in zero_cells:
        grid[r][c] = 1
    for r in range(target[0], target[0]+bh):
        for c in range(target[1], target[1]+bw):
            grid[r][c] = 0
    return grid

