def solve(grid):
    grid = [row[:] for row in grid]
    H = len(grid)
    W = len(grid[0])
    one_positions = [(r,c) for r in range(H) for c in range(W) if grid[r][c] == 1]
    one_count = len(one_positions)
    if not one_positions:
        return grid
    border_positions = [(r,c) for r in range(H) for c in range(W) if grid[r][c] not in (0, 1)]
    avg_1_c = sum(c for r,c in one_positions) / len(one_positions)
    avg_b_c = sum(c for r,c in border_positions) / len(border_positions)
    dc = avg_1_c - avg_b_c
    for r, c in one_positions:
        grid[r][c] = 0
    pocket = set()
    for r in range(H):
        borders = [c for c in range(W) if grid[r][c] != 0]
        if not borders:
            continue
        border_colors = {}
        for c in borders:
            border_colors.setdefault(grid[r][c], []).append(c)
        for color, cols in border_colors.items():
            if len(cols) >= 2:
                for c in range(min(cols)+1, max(cols)):
                    if grid[r][c] == 0:
                        pocket.add((r, c))
        if dc > 0:
            rightmost = max(borders)
            for c in range(rightmost+1, W):
                if grid[r][c] == 0:
                    pocket.add((r, c))
        elif dc < 0:
            leftmost = min(borders)
            for c in range(0, leftmost):
                if grid[r][c] == 0:
                    pocket.add((r, c))
    for c in range(W):
        borders = [r for r in range(H) if grid[r][c] != 0]
        if not borders:
            continue
        border_colors = {}
        for r in borders:
            border_colors.setdefault(grid[r][c], []).append(r)
        for color, rows in border_colors.items():
            if len(rows) >= 2:
                for r in range(min(rows)+1, max(rows)):
                    if grid[r][c] == 0:
                        pocket.add((r, c))
    pocket_sorted = sorted(pocket, key=lambda rc: (-rc[0], -rc[1]))
    filled = 0
    for r, c in pocket_sorted:
        if filled >= one_count:
            break
        grid[r][c] = 1
        filled += 1
    return grid

