def solve(grid):
    from collections import deque
    from itertools import combinations
    grid = [row[:] for row in grid]
    H = len(grid)
    W = len(grid[0])
    bg = 8

    visited = [[False]*W for _ in range(H)]
    components = []

    def bfs(sr, sc):
        q = deque([(sr, sc)])
        visited[sr][sc] = True
        cells = []
        while q:
            r, c = q.popleft()
            cells.append((r, c, grid[r][c]))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and not visited[nr][nc] and grid[nr][nc] != bg:
                    visited[nr][nc] = True
                    q.append((nr, nc))
        return cells

    for r in range(H):
        for c in range(W):
            if not visited[r][c] and grid[r][c] != bg:
                components.append(bfs(r, c))

    by_color = {}
    for comp in components:
        color = comp[0][2]
        by_color.setdefault(color, []).append(comp)

    size2_comps = [c for c in components if len(c) == 2]

    def comp_center(comp):
        return (sum(r for r,c,v in comp)/len(comp), sum(c for r,c,v in comp)/len(comp))

    # Find the 4 size-2 components forming the tightest cross (minimum max pairwise distance)
    comp_centers = [(comp, comp_center(comp)) for comp in size2_comps]

    best_group = None
    best_score = float('inf')
    for group in combinations(range(len(comp_centers)), 4):
        # Must have 4 different colors
        colors = set(comp_centers[i][0][0][2] for i in group)
        if len(colors) < 4:
            continue
        pts = [comp_centers[i][1] for i in group]
        max_dist = 0
        for i in range(4):
            for j in range(i+1, 4):
                d = abs(pts[i][0]-pts[j][0]) + abs(pts[i][1]-pts[j][1])
                max_dist = max(max_dist, d)
        if max_dist < best_score:
            best_score = max_dist
            best_group = group

    if best_group is None:
        return grid

    arm_list = [comp_centers[i] for i in best_group]
    avg_r = sum(c[1][0] for c in arm_list) / 4
    avg_c = sum(c[1][1] for c in arm_list) / 4

    arm_comps = {}
    arm_info = {}
    for comp, (cr, cc) in arm_list:
        color = comp[0][2]
        arm_comps[color] = comp
        dr = cr - avg_r
        dc = cc - avg_c
        if abs(dr) > abs(dc):
            direction = 'DOWN' if dr > 0 else 'UP'
        else:
            direction = 'RIGHT' if dc > 0 else 'LEFT'
        arm_info[color] = (direction, comp)

    external_shapes = {}
    for color, comps in by_color.items():
        ext_cells = []
        for comp in comps:
            if comp is not arm_comps.get(color):
                ext_cells.extend(comp)
        if ext_cells:
            external_shapes[color] = ext_cells

    def normalize(shape):
        mr = min(dr for dr,dc in shape)
        mc = min(dc for dr,dc in shape)
        return [(dr-mr, dc-mc) for dr,dc in shape]

    def rotate_cw(shape):
        return normalize([(dc, -dr) for dr, dc in shape])

    def hflip(shape):
        mx = max(dc for dr,dc in shape)
        return normalize([(dr, mx-dc) for dr,dc in shape])

    def all_orientations(shape):
        results = []
        cur = list(shape)
        for _ in range(4):
            results.append(tuple(sorted(cur)))
            results.append(tuple(sorted(hflip(cur))))
            cur = rotate_cw(cur)
        seen = set()
        unique = []
        for r in results:
            if r not in seen:
                seen.add(r)
                unique.append(list(r))
        return unique

    for color, ext_cells in external_shapes.items():
        if color not in arm_info:
            for r, c, v in ext_cells:
                grid[r][c] = bg
            continue

        direction, arm_comp = arm_info[color]
        arm_cells = [(r, c) for r, c, v in arm_comp]
        arm_rs = sorted(set(r for r,c in arm_cells))
        arm_cs = sorted(set(c for r,c in arm_cells))
        arm_h = len(arm_rs)
        arm_w = len(arm_cs)

        ext_min_r = min(r for r,c,v in ext_cells)
        ext_min_c = min(c for r,c,v in ext_cells)
        shape = [(r - ext_min_r, c - ext_min_c) for r,c,v in ext_cells]

        candidates = []
        for rotated in all_orientations(shape):
            sh = max(dr for dr,dc in rotated) + 1
            sw = max(dc for dr,dc in rotated) + 1

            if direction in ('LEFT', 'RIGHT'):
                aspect_ok = sh >= sw
            else:
                aspect_ok = sw >= sh

            place_r = place_c = None

            if direction == 'LEFT':
                edge_col = sw - 1
                edge_rows = sorted(dr for dr,dc in rotated if dc == edge_col)
                if len(edge_rows) == arm_h and all(edge_rows[i+1]==edge_rows[i]+1 for i in range(len(edge_rows)-1)):
                    place_r = arm_rs[0] - edge_rows[0]
                    place_c = arm_cs[0] - sw
            elif direction == 'RIGHT':
                edge_col = 0
                edge_rows = sorted(dr for dr,dc in rotated if dc == edge_col)
                if len(edge_rows) == arm_h and all(edge_rows[i+1]==edge_rows[i]+1 for i in range(len(edge_rows)-1)):
                    place_r = arm_rs[0] - edge_rows[0]
                    place_c = arm_cs[-1] + 1
            elif direction == 'UP':
                edge_row = sh - 1
                edge_cols = sorted(dc for dr,dc in rotated if dr == edge_row)
                if len(edge_cols) == arm_w and all(edge_cols[i+1]==edge_cols[i]+1 for i in range(len(edge_cols)-1)):
                    place_r = arm_rs[0] - sh
                    place_c = arm_cs[0] - edge_cols[0]
            elif direction == 'DOWN':
                edge_row = 0
                edge_cols = sorted(dc for dr,dc in rotated if dr == edge_row)
                if len(edge_cols) == arm_w and all(edge_cols[i+1]==edge_cols[i]+1 for i in range(len(edge_cols)-1)):
                    place_r = arm_rs[-1] + 1
                    place_c = arm_cs[0] - edge_cols[0]

            if place_r is not None:
                candidates.append((aspect_ok, rotated, place_r, place_c))

        candidates.sort(key=lambda x: (not x[0],))
        if candidates:
            _, rotated, place_r, place_c = candidates[0]
            for r, c, v in ext_cells:
                grid[r][c] = bg
            for dr, dc in rotated:
                nr, nc = place_r + dr, place_c + dc
                if 0 <= nr < H and 0 <= nc < W:
                    grid[nr][nc] = color
        else:
            for r, c, v in ext_cells:
                grid[r][c] = bg

    return grid
